+impl App {
+    fn new() -> Self {
+        let ctx = Arc::new(ThemeContext::from_preset(ThemePreset::Dark));
+        let styles = Styles::new(ctx.clone());
+        Self {
+            ctx,
+            styles,
+            current_theme: 0,
